BerryItem.descriptionGetter:
get description(): string {
        return `Obtain a ${this.berryName}<br/><i>(No Oak Item challenge runs only)</i>`;
    }

PokeBlock.descriptionGetter:
get description(): string {
        return this._description || 'Unobtainable item for future uses';
    }

MegaStoneItem.descriptionGetter:
get description(): string {
        return this._description || `A Mega Stone for ${this.basePokemon}.`;
    }

ChristmasPresent.descriptionGetter:
get description(): string {
        return 'A lovely Christmas Present.';
    }

FarmHandItem.descriptionGetter:
get description(): string {
        const farmHand = this.farmHand;
        return `Cost: <img alt="Farm Points" src="assets/images/currency/farmPoint.svg" width="20px">&nbsp;${(farmHand?.cost?.amount ?? 0).toLocaleString('en-US')}/hour<br/>
        Work Speed: ${GameConstants.formatTimeFullLetters((farmHand?.workTick ?? GameConstants.MINUTE) / 1000)}<br/>
        Efficiency: ${(farmHand?.efficiency ?? 0).toLocaleString('en-US')}<br/>
        Max Energy: ${(farmHand?.maxEnergy ?? 0).toLocaleString('en-US')}`;
    }

HatcheryHelperItem.descriptionGetter:
get description(): string {
        const hatcheryHelper = this.hatcheryHelper;
        return `Cost: <img src="assets/images/currency/${GameConstants.Currency[hatcheryHelper?.cost?.currency]}.svg" width="20px">&nbsp;${(hatcheryHelper?.cost?.amount ?? 0).toLocaleString('en-US')}/hatch<br/>
        Step Efficiency: ${(hatcheryHelper?.stepEfficiencyBase ?? 0).toLocaleString('en-US')}%<br/>
        Attack Efficiency: ${(hatcheryHelper?.attackEfficiencyBase ?? 0).toLocaleString('en-US')}%`;
    }
